mapper.select:
SELECT 아이디 AS userId, 이름 AS memberName, 지점 AS branch FROM J_참여자관리_로그인정보 WHERE 아이디사용여부 = '사용'
AND 지점 = #{searchBranch}
ORDER BY 지점, 조회순서, 이름

SELECT A.구직번호 jobNo, A.참여자 participantName, CONVERT(varchar, A.생년월일, 23) birthDate, A.성별 gender, A.지점 branch, A.전담자_계정 counselorAccount, M.이름 counselorName, A.진행단계 progressStage, A.모집경로 recruitPath, A.참여유형 participationType, A.경력 career, A.학력 education, A.특정계층 specialClass, A.취업역량 employmentCapacity, (SELECT TOP 1 W.희망직무 FROM J_참여자관리_희망직무 W WHERE W.구직번호 = A.구직번호 ORDER BY W.희망순위) desiredJob, A.희망급여 desiredSalary, CONVERT(varchar, A.등록일, 23) participantRegDate, A.마감 closed FROM J_참여자관리 A LEFT JOIN J_참여자관리_로그인정보 M ON A.전담자_계정 = M.아이디 WHERE 1=1
AND CAST(A.구직번호 AS NVARCHAR) LIKE #{searchJobNo} + '%'
AND A.참여자 LIKE '%' + #{searchName} + '%'
AND A.지점 = #{searchBranch}
AND A.전담자_계정 = #{searchCounselor}
AND A.진행단계 = #{searchStatus}
AND A.등록일 >= CAST(#{searchStartDate} AS date)
AND A.등록일 < DATEADD(day, 1, CAST(#{searchEndDate} AS date))
AND A.마감 = #{searchClosed}
ORDER BY A.구직번호 DESC

WITH fiscal_dates AS ( SELECT DATEFROMPARTS( CASE WHEN MONTH(GETDATE()) >= 11 THEN YEAR(GETDATE()) ELSE YEAR(GETDATE()) - 1 END, 11, 1) AS start_date, DATEFROMPARTS( CASE WHEN MONTH(GETDATE()) >= 11 THEN YEAR(GETDATE()) + 1 ELSE YEAR(GETDATE()) END, 10, 31) AS end_date ), base AS ( SELECT P.*, NULLIF(CASE WHEN 취창업일 > '1900-01-01' THEN 취창업일 WHEN 기간만료일 > '1900-01-01' THEN 기간만료일 END, '1900-01-01') AS 실제종료일 FROM J_참여자관리 P WHERE 지점 NOT IN ('테스트','공통') AND ISNULL(모집경로,'') <> '이관' AND ISNULL(참여유형,'') <> '이관' AND 진행단계 <> '취소'
AND P.지점 = #{searchBranch}
AND P.전담자_계정 = #{searchCounselor}
), scored AS ( SELECT B.지점, B.전담자_계정, CASE WHEN B.진행단계 IN ('미고보/인력공급업','고보일반','등록창업','미등록창업','미취업사후관리','미취업사후종료','중단') AND B.실제종료일 BETWEEN F.start_date AND F.end_date AND B.기간만료일 >= F.start_date THEN 1 ELSE 0 END AS 종료_F, CASE WHEN B.취창업일 >= F.start_date AND B.진행단계 IN ('등록창업','고보일반','미취업사후종료','중단') AND (B.취업인센티브_구분 NOT LIKE '%파견%' OR B.취업인센티브_구분 IS NULL) THEN 1 ELSE 0 END AS 취업_F, CASE WHEN B.취업유형 IN ('알선', '외부 알선') THEN 1 ELSE 0 END AS 알선_F FROM base B CROSS JOIN fiscal_dates F ) SELECT S.지점 AS branch, S.전담자_계정 AS counselorAccount, M.이름 AS counselorName, SUM(S.종료_F) AS completedCount, SUM(S.종료_F * S.취업_F) AS employedCount, SUM(S.종료_F * S.취업_F * S.알선_F) AS placementEmployedCount, CASE WHEN SUM(S.종료_F) = 0 THEN 0.0 ELSE CAST(SUM(S.종료_F * S.취업_F) AS FLOAT) / SUM(S.종료_F) * 100 END AS employmentRate FROM scored S LEFT JOIN J_참여자관리_로그인정보 M ON S.전담자_계정 = M.아이디 GROUP BY S.지점, S.전담자_계정, M.이름 ORDER BY S.지점, M.이름

SELECT BR.지점 AS branchLabel, ISNULL(S.cnt, 0) AS linkageCount FROM J_참여자관리_지점 BR LEFT JOIN ( SELECT B.지점, COUNT(*) AS cnt FROM J_참여자관리 A JOIN J_참여자관리_로그인정보 B ON A.전담자_계정 = B.아이디 WHERE A.연계유형 IS NOT NULL AND A.연계유형 != ''
AND A.연계일 >= #{searchStartDate}
AND A.연계일 <= #{searchEndDate}
GROUP BY B.지점 ) S ON BR.지점 = S.지점 WHERE BR.사용여부 = '사용' AND BR.지점 != '테스트'
AND BR.지점 = #{searchBranch}
ORDER BY linkageCount DESC

SELECT B.이름 AS counselorName, B.아이디 AS counselorAccount, COUNT(*) AS linkageCount FROM J_참여자관리 A JOIN J_참여자관리_로그인정보 B ON A.전담자_계정 = B.아이디 WHERE A.연계유형 IS NOT NULL AND A.연계유형 != '' AND B.지점 != '테스트' AND B.지점 = #{searchBranch}
AND A.연계일 >= #{searchStartDate}
AND A.연계일 <= #{searchEndDate}
GROUP BY B.이름, B.아이디 ORDER BY linkageCount DESC

SELECT
    A.연계유형 AS linkageType,
    COUNT(*) AS linkageCount
FROM J_참여자관리 A
JOIN J_참여자관리_로그인정보 B ON A.전담자_계정 = B.아이디
WHERE A.연계유형 IS NOT NULL AND A.연계유형 != ''
    AND B.지점 != '테스트'

    AND B.지점 = #{searchBranch}


    AND A.전담자_계정 = #{searchCounselor}


    AND  A.연계일 >= #{searchStartDate} 


    AND  A.연계일 <= #{searchEndDate} 

GROUP BY A.연계유형
ORDER BY linkageCount DESC

SET ANSI_WARNINGS OFF; SET ARITHIGNORE ON; SET ARITHABORT OFF;
WITH 배정 AS ( SELECT 지점, COUNT(*) AS 배정인원 FROM J_참여자관리 WHERE YEAR(IIF((초기상담일 = '1900-01-01' OR 초기상담일 IS NULL), 등록일, ISNULL(초기상담일, ''))) = #{searchYear} AND 모집경로 <> '이관' AND 진행단계 <> '취소' GROUP BY 지점 ), 자체모집 AS ( SELECT 지점, COUNT(*) AS 자체모집인원 FROM J_참여자관리 WHERE YEAR(IIF((초기상담일 = '1900-01-01' OR 초기상담일 IS NULL), 등록일, ISNULL(초기상담일, ''))) = #{searchYear} AND 참여유형 = '1' AND 모집경로 <> '이관' AND 진행단계 <> '취소' GROUP BY 지점 ), 참여자 AS ( SELECT 지점, COUNT(*) AS 참여자수 FROM J_참여자관리 WHERE YEAR(IIF((초기상담일 = '1900-01-01' OR 초기상담일 IS NULL), 등록일, ISNULL(초기상담일, ''))) = #{searchYear} AND 마감 = 'false' AND 진행단계 NOT IN ('취소', '이관') GROUP BY 지점 ), 취소_원본 AS ( SELECT 구직번호, 지점 FROM J_참여자관리 WHERE YEAR(IIF((초기상담일 = '1900-01-01' OR 초기상담일 IS NULL), 등록일, ISNULL(초기상담일, ''))) = #{searchYear} AND 진행단계 = '취소' ), 취소_백업 AS ( SELECT 구직번호, 지점 FROM J_참여자관리_취소자백업 WHERE YEAR(ISNULL(참여자_등록일, 취소자백업_등록일)) = #{searchYear} ), 취소_통합 AS ( SELECT DISTINCT 구직번호, 지점 FROM 취소_원본 UNION SELECT DISTINCT 구직번호, 지점 FROM 취소_백업 ), 취소 AS ( SELECT 지점, COUNT(*) AS 취소인원 FROM 취소_통합 GROUP BY 지점 ), 상담사 AS ( SELECT 지점, SUM( CASE WHEN 입사일 IS NULL OR 입사일 = '' THEN 0 ELSE CAST( DATEDIFF(MONTH, IIF(YEAR(입사일) < CAST(#{searchYear} AS INT), DATEFROMPARTS(CAST(#{searchYear} AS INT), 1, 1), 입사일), IIF(퇴사일 IS NOT NULL AND 퇴사일 <> '' AND YEAR(퇴사일) = CAST(#{searchYear} AS INT), 퇴사일, IIF(YEAR(입사일) > CAST(#{searchYear} AS INT), 입사일, DATEFROMPARTS(CAST(#{searchYear} AS INT), 12, 31))) ) AS FLOAT) / 12.0 END ) AS 상담사수 FROM J_참여자관리_로그인정보 WHERE 아이디사용여부 NOT IN ('승인대기', '잠금', '정지', '퇴사', '사용대기') AND (YEAR(입사일) <= CAST(#{searchYear} AS INT)) AND (퇴사일 IS NULL OR 퇴사일 = '' OR YEAR(퇴사일) >= CAST(#{searchYear} AS INT)) GROUP BY 지점 ) SELECT B.지점 AS branchName, ISNULL(배정.배정인원, 0) AS assignedCount, ISNULL(자체모집.자체모집인원, 0) AS selfRecruitCount, ISNULL(참여자.참여자수, 0) AS activeParticipantCount, ISNULL(취소.취소인원, 0) AS canceledCount, ROUND(ISNULL(상담사.상담사수, 0), 2) AS counselorWeighted, IIF(ISNULL(상담사.상담사수, 0) = 0, 0, ROUND(CAST(ISNULL(참여자.참여자수, 0) AS FLOAT) / 상담사.상담사수, 1) ) AS counselorLoad FROM J_참여자관리_지점 B LEFT JOIN 배정 ON B.지점 = 배정.지점 LEFT JOIN 자체모집 ON B.지점 = 자체모집.지점 LEFT JOIN 참여자 ON B.지점 = 참여자.지점 LEFT JOIN 취소 ON B.지점 = 취소.지점 LEFT JOIN 상담사 ON B.지점 = 상담사.지점 WHERE B.사용여부 = '사용' AND B.지점 <> '테스트'
AND B.지점 = #{searchBranch}
ORDER BY B.순서 ASC
